import{c as a,cG as s,cb as i,c8 as e,cf as t,cT as n,ce as l}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"OpenClaw","description":"","frontmatter":{"title":"OpenClaw","categories":"foo","tags":"bar","sidebar":false,"prev":false,"next":false,"comments":false,"date":"2026-04-22T10:35:36.000Z"},"headers":[],"relativePath":"posts/2026/04_22_OpenClaw.md","filePath":"posts/2026/04_22_OpenClaw.md","lastUpdated":1778149631000}'),r={id:"frontmatter-title",tabindex:"-1"};const d=a({name:"posts/2026/04_22_OpenClaw.md"},[["render",function(a,h,d,p,o,c){return s(),i("div",null,[e("h1",r,[t(n(a.$frontmatter.title)+" ",1),h[0]||(h[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=l('<p>好的，基于我对 OpenClaw 的了解和你的环境，给你一份循序渐进的教程：</p><hr><h1 id="openclaw-研发工作流教程" tabindex="-1">OpenClaw 研发工作流教程 <a class="header-anchor" href="#openclaw-研发工作流教程" aria-label="Permalink to “OpenClaw 研发工作流教程”">​</a></h1><h2 id="第一阶段-认识-openclaw-1-2-天" tabindex="-1">第一阶段：认识 OpenClaw（1-2 天） <a class="header-anchor" href="#第一阶段-认识-openclaw-1-2-天" aria-label="Permalink to “第一阶段：认识 OpenClaw（1-2 天）”">​</a></h2><h3 id="_1-1-openclaw-是什么" tabindex="-1">1.1 OpenClaw 是什么 <a class="header-anchor" href="#_1-1-openclaw-是什么" aria-label="Permalink to “1.1 OpenClaw 是什么”">​</a></h3><p>OpenClaw 是一个 <strong>AI Agent 网关</strong>，核心思路是：一个 AI 助手连接你的所有工具（终端、消息、文件、日历等），通过自然语言执行任务。</p><h3 id="_1-2-核心概念" tabindex="-1">1.2 核心概念 <a class="header-anchor" href="#_1-2-核心概念" aria-label="Permalink to “1.2 核心概念”">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td><strong>Gateway</strong></td><td>后台服务，管理所有连接和 Agent 运行</td></tr><tr><td><strong>Session</strong></td><td>一次对话，可以是 Web、Discord、飞书等</td></tr><tr><td><strong>Workspace</strong></td><td>Agent 的工作目录，存放文件和记忆</td></tr><tr><td><strong>Skill</strong></td><td>专门技能（如 coding-agent、weather）</td></tr><tr><td><strong>Cron</strong></td><td>定时任务（提醒、定期检查）</td></tr><tr><td><strong>Heartbeat</strong></td><td>Agent 主动轮询检查的机制</td></tr></tbody></table><h3 id="_1-3-常用命令" tabindex="-1">1.3 常用命令 <a class="header-anchor" href="#_1-3-常用命令" aria-label="Permalink to “1.3 常用命令”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 查看整体状态</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Gateway 是否在跑</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 健康检查</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dashboard</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 打开 Web 控制台（就是你现在用的）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configure</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 交互式配置</span></span></code></pre></div><hr><h2 id="第二阶段-基础对话与工具使用-2-3-天" tabindex="-1">第二阶段：基础对话与工具使用（2-3 天） <a class="header-anchor" href="#第二阶段-基础对话与工具使用-2-3-天" aria-label="Permalink to “第二阶段：基础对话与工具使用（2-3 天）”">​</a></h2><h3 id="_2-1-直接在-web-ui-对话" tabindex="-1">2.1 直接在 Web UI 对话 <a class="header-anchor" href="#_2-1-直接在-web-ui-对话" aria-label="Permalink to “2.1 直接在 Web UI 对话”">​</a></h3><p>你现在已经在做了。试试这些：</p><ul><li>&quot;帮我查一下今天的天气&quot;</li><li>&quot;读取当前目录下的文件列表&quot;</li><li>&quot;帮我搜索一下 xxx 的信息&quot;</li></ul><h3 id="_2-2-理解-workspace" tabindex="-1">2.2 理解 Workspace <a class="header-anchor" href="#_2-2-理解-workspace" aria-label="Permalink to “2.2 理解 Workspace”">​</a></h3><p>Agent 的工作目录是 <code>~/.openclaw/workspace/</code>，关键文件：</p><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>SOUL.md</code></td><td>Agent 的人格和行为准则</td></tr><tr><td><code>AGENTS.md</code></td><td>Agent 的工作规范</td></tr><tr><td><code>MEMORY.md</code></td><td>长期记忆（重要决策、偏好）</td></tr><tr><td><code>memory/YYYY-MM-DD.md</code></td><td>每日笔记</td></tr><tr><td><code>TOOLS.md</code></td><td>工具配置备忘</td></tr><tr><td><code>IDENTITY.md</code></td><td>Agent 身份信息</td></tr></tbody></table><h3 id="_2-3-练习-让-agent-管理文件" tabindex="-1">2.3 练习：让 Agent 管理文件 <a class="header-anchor" href="#_2-3-练习-让-agent-管理文件" aria-label="Permalink to “2.3 练习：让 Agent 管理文件”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮我在 workspace 里创建一个 notes/ 文件夹，写一个项目计划&quot;</span></span>\n<span class="line"><span>&quot;把今天的会议记录整理到 memory/2026-04-22.md&quot;</span></span></code></pre></div><hr><h2 id="第三阶段-连接外部工具与平台-3-5-天" tabindex="-1">第三阶段：连接外部工具与平台（3-5 天） <a class="header-anchor" href="#第三阶段-连接外部工具与平台-3-5-天" aria-label="Permalink to “第三阶段：连接外部工具与平台（3-5 天）”">​</a></h2><h3 id="_3-1-配置聊天渠道" tabindex="-1">3.1 配置聊天渠道 <a class="header-anchor" href="#_3-1-配置聊天渠道" aria-label="Permalink to “3.1 配置聊天渠道”">​</a></h3><p>你已经连了飞书。可以再连：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configure</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 选择 channels 配置</span></span></code></pre></div><p>支持：飞书、Discord、Telegram、Slack、WhatsApp 等</p><h3 id="_3-2-练习-多平台联动" tabindex="-1">3.2 练习：多平台联动 <a class="header-anchor" href="#_3-2-练习-多平台联动" aria-label="Permalink to “3.2 练习：多平台联动”">​</a></h3><ul><li>从飞书给 Agent 发消息，让它在 Web 端处理任务</li><li>让 Agent 帮你读飞书文档（feishu-doc skill）</li></ul><h3 id="_3-3-cron-定时任务" tabindex="-1">3.3 Cron 定时任务 <a class="header-anchor" href="#_3-3-cron-定时任务" aria-label="Permalink to “3.3 Cron 定时任务”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;每天早上 9 点提醒我看邮件&quot;</span></span>\n<span class="line"><span>&quot;每周五下午 5 点提醒我写周报&quot;</span></span></code></pre></div><p>Agent 会用 cron 工具创建定时任务。</p><hr><h2 id="第四阶段-coding-agent-研发工作流-1-2-周-🔥" tabindex="-1">第四阶段：Coding Agent 研发工作流（1-2 周）🔥 <a class="header-anchor" href="#第四阶段-coding-agent-研发工作流-1-2-周-🔥" aria-label="Permalink to “第四阶段：Coding Agent 研发工作流（1-2 周）🔥”">​</a></h2><p>这是你最关心的部分。</p><h3 id="_4-1-coding-agent-是什么" tabindex="-1">4.1 Coding Agent 是什么 <a class="header-anchor" href="#_4-1-coding-agent-是什么" aria-label="Permalink to “4.1 Coding Agent 是什么”">​</a></h3><p>OpenClaw 可以把编码任务委托给专业编程 Agent（Codex、Claude Code 等），Agent 会在你的项目目录里直接读代码、写代码、跑命令。</p><h3 id="_4-2-基础用法" tabindex="-1">4.2 基础用法 <a class="header-anchor" href="#_4-2-基础用法" aria-label="Permalink to “4.2 基础用法”">​</a></h3><p>直接告诉我：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮我在 ~/projects/my-app 里添加一个用户登录功能&quot;</span></span>\n<span class="line"><span>&quot;帮我看一下 ~/projects/api 这个项目的 bug，最近 CI 挂了&quot;</span></span>\n<span class="line"><span>&quot;重构 ~/projects/frontend/src/utils.ts，提取公共函数&quot;</span></span></code></pre></div><p>我会启动一个 coding agent 子进程来完成任务。</p><h3 id="_4-3-高级用法-自动化研发流程" tabindex="-1">4.3 高级用法：自动化研发流程 <a class="header-anchor" href="#_4-3-高级用法-自动化研发流程" aria-label="Permalink to “4.3 高级用法：自动化研发流程”">​</a></h3><p><strong>① 代码审查</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮我 review 这个 PR 的改动：git diff main...feature-branch&quot;</span></span></code></pre></div><p><strong>② Git 工作流</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮我把当前分支的改动 commit 并 push 到 origin&quot;</span></span>\n<span class="line"><span>&quot;创建一个新分支 feature/xxx 并切换过去&quot;</span></span></code></pre></div><p><strong>③ 调试与修复</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;跑一下测试看看哪里挂了：cd ~/projects/app &amp;&amp; npm test&quot;</span></span>\n<span class="line"><span>&quot;帮我分析这个报错日志：/tmp/error.log&quot;</span></span></code></pre></div><p><strong>④ 文档生成</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮这个项目生成 README.md&quot;</span></span>\n<span class="line"><span>&quot;把 src/ 下的代码生成 API 文档&quot;</span></span></code></pre></div><h3 id="_4-4-搭建自动化流水线" tabindex="-1">4.4 搭建自动化流水线 <a class="header-anchor" href="#_4-4-搭建自动化流水线" aria-label="Permalink to “4.4 搭建自动化流水线”">​</a></h3><p>用 Cron + Coding Agent 组合：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;每天早上 10 点检查 ~/projects/main 的 CI 状态，如果有失败的告诉我&quot;</span></span>\n<span class="line"><span>&quot;每次 push 到 main 后自动跑测试&quot;</span></span></code></pre></div><hr><h2 id="第五阶段-skill-开发与定制-进阶" tabindex="-1">第五阶段：Skill 开发与定制（进阶） <a class="header-anchor" href="#第五阶段-skill-开发与定制-进阶" aria-label="Permalink to “第五阶段：Skill 开发与定制（进阶）”">​</a></h2><h3 id="_5-1-现成-skills" tabindex="-1">5.1 现成 Skills <a class="header-anchor" href="#_5-1-现成-skills" aria-label="Permalink to “5.1 现成 Skills”">​</a></h3><p>你已经有很多可用技能：</p><ul><li><code>coding-agent</code> — 编程任务</li><li><code>github</code> — GitHub 操作（Issue、PR）</li><li><code>feishu-doc/wiki</code> — 飞书文档</li><li><code>weather</code> — 天气查询</li><li><code>healthcheck</code> — 安全审计</li><li><code>taskflow</code> — 持久化工作流</li></ul><h3 id="_5-2-自定义-skill" tabindex="-1">5.2 自定义 Skill <a class="header-anchor" href="#_5-2-自定义-skill" aria-label="Permalink to “5.2 自定义 Skill”">​</a></h3><p>如果现有技能不够用，可以创建自己的 Skill：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮我创建一个 skill，用于自动化我们的部署流程&quot;</span></span></code></pre></div><p>Skill 本质上是一个 <code>SKILL.md</code> 指令文件 + 可选的脚本。</p><hr><h2 id="第六阶段-实战案例-—-研发工作流" tabindex="-1">第六阶段：实战案例 — 研发工作流 <a class="header-anchor" href="#第六阶段-实战案例-—-研发工作流" aria-label="Permalink to “第六阶段：实战案例 — 研发工作流”">​</a></h2><h3 id="案例-1-需求-→-开发-→-测试-→-部署" tabindex="-1">案例 1：需求 → 开发 → 测试 → 部署 <a class="header-anchor" href="#案例-1-需求-→-开发-→-测试-→-部署" aria-label="Permalink to “案例 1：需求 → 开发 → 测试 → 部署”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你: &quot;我需要给项目添加一个导出 CSV 功能&quot;</span></span>\n<span class="line"><span>Agent: [启动 coding agent] 分析项目 → 写代码 → 跑测试 → 提交 PR</span></span></code></pre></div><h3 id="案例-2-日常研发辅助" tabindex="-1">案例 2：日常研发辅助 <a class="header-anchor" href="#案例-2-日常研发辅助" aria-label="Permalink to “案例 2：日常研发辅助”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;帮我看看今天有哪些 GitHub Issue 需要处理&quot;</span></span>\n<span class="line"><span>&quot;帮我把这个 Jira ticket 的需求翻译成技术方案&quot;</span></span>\n<span class="line"><span>&quot;分析一下最近一周的代码提交频率&quot;</span></span></code></pre></div><h3 id="案例-3-知识管理" tabindex="-1">案例 3：知识管理 <a class="header-anchor" href="#案例-3-知识管理" aria-label="Permalink to “案例 3：知识管理”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;把今天学到的技术点记录到 memory/&quot;</span></span>\n<span class="line"><span>&quot;帮我整理一下项目架构文档&quot;</span></span></code></pre></div><hr><h2 id="推荐学习路径总结" tabindex="-1">推荐学习路径总结 <a class="header-anchor" href="#推荐学习路径总结" aria-label="Permalink to “推荐学习路径总结”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第 1 天: 熟悉 Web UI，尝试基本对话</span></span>\n<span class="line"><span>第 2-3 天: 让 Agent 操作文件、管理记忆</span></span>\n<span class="line"><span>第 4-5 天: 配置飞书/Discord，体验多平台</span></span>\n<span class="line"><span>第 1 周:  用 Coding Agent 完成实际编码任务</span></span>\n<span class="line"><span>第 2 周:  搭建自动化 Cron 任务（CI 检查、日报提醒等）</span></span>\n<span class="line"><span>第 3 周+: 学习自定义 Skill，深度定制工作流</span></span></code></pre></div><hr><p>有任何阶段想深入，直接告诉我，我可以手把手带你操作。比如现在就可以试试：&quot;帮我看看 ~/projects/ 下面有什么项目，挑一个做点实际的。&quot;</p>',74))])}]]);export{h as __pageData,d as default};
